/**
 * Handle mode-switching intents. Returns true if consumed.
 */
export function handleModeSwitch(intentType: string, topic: string|undefined, question: string|undefined, cb: DispatchCallbacks): boolean {
  if (intentType === 'campfire' && !topic) {
    cb.setMode('campfire');
    cb.dispatch({ type: 'success', message: 'Switched to campfire mode — just talk, all engines think together' });
    return true;
  }
  if (intentType === 'brainstorm' && !question) {
    cb.setMode('brainstorm');
    cb.dispatch({ type: 'success', message: 'Switched to brainstorm mode — engines bid on your questions' });
    return true;
  }
  if (intentType === 'tribunal' && !question) {
    cb.setMode('tribunal');
    cb.dispatch({ type: 'success', message: 'Switched to tribunal mode — engines debate your questions' });
    return true;
  }
  if (intentType === 'chat') {
    if (cb.mode !== 'chat') {
      cb.setMode('chat');
      cb.dispatch({ type: 'success', message: 'Switched to chat mode' });
    }
    return false; // May have input to process
  }
  return false;
}

/**
 * Extract a fitness command from conversational execution input while keeping the task clean.
 */
export function extractExecutionSpec(input: string): { task:string; fitnessCmd:string|null } {
  const fitnessMatch = FITNESS_PATTERN.exec(input);
  const fitnessCmd = fitnessMatch ? fitnessMatch[1].trim() : null;
  const task = fitnessCmd
    ? input.replace(FITNESS_PATTERN, '').trim()
    : input.trim();
  return { task, fitnessCmd };
}

/**
 * Send a message directly into Cesar's persistent session and stream the response. Returns the response text.
 */
export async function absorbIntoCesar(message: string, dispatch: Dispatch, ctx: HandlerContext): Promise<string> {
  const session = ctx.cesarSession;
  if (!session || !session.alive) return '';
  
  const cesarEngineId = (ctx.config as any).cesarEngine ?? ctx.config.forgeFixedStarter ?? 'claude';
  const color = ENGINE_COLORS[cesarEngineId] ?? 124;
  
  let response = '';
  let streaming = false;
  const gen = session.send({ message });
  
  for await (const chunk of gen) {
    if (chunk.type === 'text') {
      if (!streaming) {
        dispatch({ type: 'spinner-stop' });
        streaming = true;
      }
      dispatch({ type: 'streaming-chunk', engineId: cesarEngineId, chunk: chunk.content });
      response += chunk.content;
    } else if (chunk.type === 'status') {
      dispatch({ type: 'spinner-update', message: `Cesar ${chunk.content}` });
    } else if (chunk.type === 'error') {
      dispatch({ type: 'error', message: chunk.content });
      break;
    } else if (chunk.type === 'done') {
      break;
    }
  }
  
  if (streaming) {
    dispatch({ type: 'streaming-end', engineId: cesarEngineId });
    await yieldToInk();
  } else {
    dispatch({ type: 'spinner-stop' });
  }
  
  response = response.replace(/<think>[\s\S]*?<\/think>\s*/gi, '').trim();
  
  if (response) {
    appendMessage(ctx.chatSession, { role: 'engine', engineId: cesarEngineId, content: response, timestamp: new Date().toISOString() });
  }
  
  return response;
}

